sql.where:
AND deleted_at IS NULL

    AND image_name ILIKE CONCAT('%', #{query.keyword}, '%')


    AND acquisition_time >= #{query.startTime}


    AND acquisition_time <= #{query.endTime}


    AND sensor_type = #{query.sensor}


    AND cloud_percent <= #{query.maxCloudPercent}


    AND footprint IS NOT NULL
    AND ST_Intersects(
        footprint,
        ST_MakeEnvelope(#{query.minLng}, #{query.minLat}, #{query.maxLng}, #{query.maxLat}, 4326)
    )

AND rs_image.deleted_at IS NULL
AND footprint IS NOT NULL
AND ST_Intersects(footprint, region.geom)

    AND acquisition_time >= #{query.startTime}


    AND acquisition_time <= #{query.endTime}


    AND sensor_type = #{query.sensor}


    AND cloud_percent <= #{query.maxCloudPercent}

mapper.select:
SELECT
FROM rs_image
ORDER BY acquisition_time DESC NULLS LAST, created_at DESC, id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT

FROM rs_image
INNER JOIN rs_admin_region region ON region.id = #{query.regionId}

ORDER BY acquisition_time DESC NULLS LAST, created_at DESC, id DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1)
FROM rs_image
INNER JOIN rs_admin_region region ON region.id = #{query.regionId}

SELECT COUNT(1)
FROM rs_image
WHERE image_code = #{imageCode}
